const e=require("fs"),n=(require("path"),e.readdirSync(__dirname).filter(e=>e.endsWith(".html")&&!e.endsWith("-static.html")));for(const t of n){let n=e.readFileSync(t,"utf8"),r=!1;const o=/<script>\s*\/\/\s*Hide initial loader when JS is ready[\s\S]*?<\/script>/;o.test(n)&&(n=n.replace(o,"<script>\n    // Hide initial loader when JS is ready and content is rendered\n    const hideInitialLoader = () => {\n        const loader = document.getElementById('initial-loader');\n        if (loader) {\n            loader.style.opacity = '0';\n            setTimeout(() => loader.remove(), 300);\n        }\n    };\n    \n    // Fallback: maximum 5 seconds\n    const fallbackTimer = setTimeout(hideInitialLoader, 5000);\n\n    // Poll for content rendering\n    const pollTimer = setInterval(() => {\n        const hasContent = document.querySelector('.product-card:not(.skeleton-card)') || \n                           (document.querySelector('.category-item') && !document.querySelector('.product-card.skeleton-card')) || \n                           document.querySelector('.admin-container') ||\n                           document.querySelector('.cart-item') ||\n                           document.querySelector('.auth-container');\n                           \n        if (hasContent) {\n            clearInterval(pollTimer);\n            clearTimeout(fallbackTimer);\n            hideInitialLoader();\n        }\n    }, 100);\n<\/script>"),r=!0),r&&(e.writeFileSync(t,n),console.log("Updated Script in:",t))}console.log("Done updating scripts!");